            htmlElement.setAttribute('data-theme', 'dark');
            document.body.style.backgroundColor = '#121212'; // Ép nền đen
            if (themeIcon) {
                themeIcon.classList.remove('fa-moon');
                themeIcon.classList.add('fa-sun'); // Đổi icon sang Mặt trời
            }
        }

